import { useState, useEffect, useRef, useCallback } from "react";

/* ═══════════════════════════════════════════════════════════
   RUBROMAP — Análise de Desempenho
   Clube de Regatas do Flamengo
═══════════════════════════════════════════════════════════ */

const LOGO_B64    = "";
const CAMPO_P_B64 = ""; // portrait
const CAMPO_L_B64 = ""; // landscape

/* ── Paleta ─────────────────────────────────────────────── */
const C = {
  red:"#E8001C", redDk:"#9B0012", redGl:"rgba(232,0,28,.35)",
  blk:"#050505", bg:"#0B0B0B", card:"#101010", card2:"#151515",
  bdr:"#1C1C1C", bdr2:"#262626",
  gold:"#C8A030", goldL:"#DEB840",
  wh:"#EFEFEF", gr:"#2E2E2E", grL:"#5E5E5E",
  pos:"#15803D", posL:"#22C55E",
  neg:"#B91C1C", negL:"#EF4444",
  blue:"#3B82F6",
};

/* ── Zonas do Campo Portrait (5 linhas × 6 colunas = 30) ── */
// Campo útil: x[2.9%,97%], y[4.4%,95.6%]
// 6 colunas verticais (esq→dir), 5 linhas horizontais (ataque→defesa)
// Linha do meio NÃO dividida em esq/dir — corredor central unificado
const FX1=0.029,FX2=0.970,FY1=0.044,FY2=0.956;
const SX=(FX2-FX1)/6, SY=(FY2-FY1)/5;
const ROW_NAMES=["Área Adv.","Ataque","Meio","Defesa","Área Própria"];
const COL_NAMES=["Lat. Esq","Semi-Esq","Centro-Esq","Centro-Dir","Semi-Dir","Lat. Dir"];
const COL_SHORT=["LE","SE","CE","CD","SD","LD"];

const ZONES_P = [];
for(let r=0;r<5;r++) for(let c=0;c<6;c++){
  ZONES_P.push({
    id:r*6+c, row:r, col:c,
    name:`${ROW_NAMES[r]} · ${COL_SHORT[c]}`,
    y1:FY1+r*SY, y2:FY1+(r+1)*SY,
    x1:FX1+c*SX, x2:FX1+(c+1)*SX,
  });
}

/* ── Zonas do Campo Landscape (campo deitado) ────────────── */
// Após rotação 90°: comprimento=antigo_y, largura=antigo_x
// 6 colunas ao longo do comprimento, 5 linhas ao longo da largura
const LX1=0.044,LX2=0.956,LY1=0.030,LY2=0.971;
const LSX=(LX2-LX1)/6, LSY=(LY2-LY1)/5;
const ZONES_L = [];
for(let r=0;r<5;r++) for(let c=0;c<6;c++){
  ZONES_L.push({
    id:r*6+c, row:r, col:c,
    name:`${ROW_NAMES[c]} · ${COL_SHORT[r]}`,  // c=coluna do comprimento=setor do jogo
    y1:LY1+r*LSY, y2:LY1+(r+1)*LSY,
    x1:LX1+c*LSX, x2:LX1+(c+1)*LSX,
  });
}

/* ── Ações ───────────────────────────────────────────────── */
const SECTORS = [
  { id:"of", label:"Ofensivo", color:"#F97316", actions:[
    { id:"gol_fav",    label:"GOL A FAVOR",            type:"single", openGoalModal:"home" },
    { id:"chegada",    label:"CHEGADA ÚLTIMO TERÇO",    type:"single" },
    { id:"finaliz",    label:"FINALIZAÇÃO",             type:"split",
      posId:"finalPos", posLabel:"CERTA",
      negId:"finalNeg", negLabel:"ERRADA" },
    { id:"drible",     label:"DRIBLE",                  type:"split",
      posId:"driblePos", posLabel:"GANHO",
      negId:"dribleNeg", negLabel:"PERDIDO" },
    { id:"um1Of",      label:"1×1 OFENSIVO",            type:"split",
      posId:"um1OfPos",  posLabel:"GANHO",
      negId:"um1OfNeg",  negLabel:"PERDIDO" },
    { id:"cruzamento", label:"CRUZAMENTO",              type:"single" },
    { id:"assistencia",label:"ASSISTÊNCIA",             type:"single" },
  ]},
  { id:"def", label:"Defensivo", color:"#60A5FA", actions:[
    { id:"gol_sofr",      label:"GOL SOFRIDO",          type:"single", openGoalModal:"away" },
    { id:"desarme",       label:"DESARME",              type:"single" },
    { id:"recuperacao",   label:"RECUPERAÇÃO",          type:"single" },
    { id:"um1Def",        label:"1×1 DEFENSIVO",        type:"split",
      posId:"um1DefPos",  posLabel:"GANHO",
      negId:"um1DefNeg",  negLabel:"PERDIDO" },
    { id:"corte",         label:"CORTE",                type:"single" },
    { id:"interceptacao", label:"INTERCEPTAÇÃO",        type:"single" },
    { id:"goleiro",       label:"AÇÃO GOLEIRO",         type:"split",
      posId:"goleiroFla", posLabel:"FLAMENGO",
      negId:"goleiroAdv", negLabel:"ADVERSÁRIO",
      posColor:C.red,     negColor:C.blue },
  ]},
  { id:"adv", label:"Advertência", color:"#EAB308", actions:[
    { id:"cartAmr",     label:"CARTÃO AMARELO",         type:"single" },
    { id:"cartVerm",    label:"CARTÃO VERMELHO",        type:"single" },
    { id:"falta",       label:"FALTA",                  type:"split",
      posId:"faltaRec", posLabel:"SOFRIDA",
      negId:"faltaCom", negLabel:"COMETIDA" },
    { id:"impedimento", label:"IMPEDIMENTO",            type:"single" },
  ]},
];

const ALL_IDS = [];
SECTORS.forEach(s=>s.actions.forEach(a=>{
  if(a.type==="single") ALL_IDS.push(a.id);
  else { ALL_IDS.push(a.posId); ALL_IDS.push(a.negId); }
}));

const initSt  = ()=>Object.fromEntries(ALL_IDS.map(id=>[id,0]));
const initZSt = ()=>Object.fromEntries([...Array(30)].map((_,i)=>[i,initSt()]));
const mkPlayers = list=>list.map(p=>({...p,stats:initSt(),zStats:initZSt()}));

const getMeta = id => {
  for(const s of SECTORS) for(const a of s.actions){
    if(a.type==="single"&&a.id===id) return {label:a.label,color:s.color,sector:s};
    if(a.type==="split"){
      if(a.posId===id) return {label:`${a.label} ${a.posLabel}`,color:a.posColor||C.posL,sector:s};
      if(a.negId===id) return {label:`${a.label} ${a.negLabel}`,color:a.negColor||C.negL,sector:s};
    }
  }
  return {label:id,color:C.grL,sector:null};
};

/* ── Elencos ─────────────────────────────────────────────── */
const POSITIONS=["Goleiro","Zagueiro","Lateral Direito","Lateral Esquerdo","Volante","Meia","Ponta","Atacante"];
const CAT_LIST=["Sub 08","Sub 09","Sub 10","Sub 11","Sub 12","Sub 13","Sub 14","Sub 15","Sub 16","Sub 17","Sub 20","Profissional","Feminino"];

const SQUADS = {
  "Sub 13":[
    {id:1, name:"Eduardo Costa",      number:"1",  pos:"Goleiro"},
    {id:2, name:"João Miguel",        number:"2",  pos:"Lateral Direito"},
    {id:3, name:"Kauê Braga",         number:"3",  pos:"Zagueiro"},
    {id:4, name:"Guilherme",          number:"4",  pos:"Zagueiro"},
    {id:5, name:"Papa",               number:"5",  pos:"Volante"},
    {id:6, name:"Bernardo Marins",    number:"6",  pos:"Ponta"},
    {id:7, name:"Enzinho",            number:"7",  pos:"Meia"},
    {id:8, name:"Miguel Vitor",       number:"8",  pos:"Volante"},
    {id:9, name:"Arthur Santana",     number:"9",  pos:"Atacante"},
    {id:10,name:"Bernardo Aiex",      number:"10", pos:"Meia"},
    {id:11,name:"Arthur Leonardo",    number:"11", pos:"Goleiro"},
    {id:12,name:"Bento",              number:"13", pos:"Zagueiro"},
    {id:13,name:"Davi Henrique",      number:"14", pos:"Volante"},
    {id:14,name:"Diego Velloso",      number:"15", pos:"Volante"},
    {id:15,name:"Pietro Andrey",      number:"16", pos:"Lateral Esquerdo"},
    {id:16,name:"Théo",               number:"17", pos:"Lateral Esquerdo"},
    {id:17,name:"Ivan",               number:"18", pos:"Ponta"},
    {id:18,name:"Enzo Gabriel",       number:"19", pos:"Atacante"},
    {id:19,name:"Vitor",              number:"19", pos:"Zagueiro"},
    {id:20,name:"Pietro Aragon",      number:"20", pos:"Volante"},
    {id:21,name:"Rhay",               number:"21", pos:"Ponta"},
    {id:22,name:"Kaio Lima",          number:"22", pos:"Lateral Direito"},
    {id:23,name:"Bernardo Praça",     number:"",   pos:"Zagueiro"},
    {id:24,name:"Guilherme Medeiros", number:"",   pos:"Goleiro"},
    {id:25,name:"Gustavo Pereira",    number:"",   pos:"Meia"},
  ],
};
CAT_LIST.forEach(k=>{ if(!SQUADS[k]) SQUADS[k]=[]; });

/* ── Botões padrão Ao Vivo ───────────────────────────────── */
const DEFAULT_LIVE_BUTTONS = [
  {id:"gol_fav",    col:0,row:0},{id:"gol_sofr",    col:1,row:0},
  {id:"chegada",    col:2,row:0},{id:"finalPos",    col:3,row:0},
  {id:"finalNeg",   col:4,row:0},{id:"assistencia", col:5,row:0},
  {id:"desarme",    col:0,row:1},{id:"recuperacao", col:1,row:1},
  {id:"um1OfPos",   col:2,row:1},{id:"um1OfNeg",   col:3,row:1},
  {id:"um1DefPos",  col:4,row:1},{id:"um1DefNeg",  col:5,row:1},
  {id:"driblePos",  col:0,row:2},{id:"dribleNeg",  col:1,row:2},
  {id:"cruzamento", col:2,row:2},{id:"interceptacao",col:3,row:2},
  {id:"corte",      col:4,row:2},{id:"cartAmr",    col:5,row:2},
  {id:"goleiroFla", col:0,row:3},{id:"goleiroAdv", col:1,row:3},
  {id:"faltaRec",   col:2,row:3},{id:"faltaCom",   col:3,row:3},
  {id:"cartVerm",   col:4,row:3},{id:"impedimento", col:5,row:3},
];

/* ════════════════════════════════════════════════════════════
   COMPONENTE PRINCIPAL
════════════════════════════════════════════════════════════ */
export default function RubroMap(){
  const [catKey,   setCatKey]   = useState("Sub 13");
  const [players,  setPlayers]  = useState(mkPlayers(SQUADS["Sub 13"]));
  const [tStats,   setTStats]   = useState(initSt());
  const [tZStats,  setTZStats]  = useState(initZSt());
  const [selPl,    setSelPl]    = useState(null);
  const [selZone,  setSelZone]  = useState(null);
  const [selAct,   setSelAct]   = useState(null);
  const [view,     setView]     = useState("ao_vivo"); // ao_vivo | heatmap | stats | elenco
  const [hist,     setHist]     = useState([]);
  const [mTime,    setMTime]    = useState(0);
  const [mRun,     setMRun]     = useState(false);
  const [score,    setScore]    = useState({fla:0,adv:0});
  const [flashZ,   setFlashZ]   = useState(null);
  const [toast,    setToast]    = useState(null);
  const [possMode, setPossMode] = useState("pause");
  const [possTime, setPossTime] = useState({fla:0,adv:0});
  const [heatFilt, setHeatFilt] = useState("all");
  const [showCat,  setShowCat]  = useState(false);
  const [showPossModal, setShowPossModal] = useState(false);
  const [goalModal,    setGoalModal]    = useState(null); // null | {side:"home"|"away", actId, zoneId}
  const [liveButtons,  setLiveButtons]   = useState(DEFAULT_LIVE_BUTTONS);
  const DEFAULT_BTN_COLORS = Object.fromEntries(
    [...SECTORS.flatMap(s=>s.actions.map(a=>
      a.type==="single"?[[a.id,s.color]]:[[a.posId,a.posColor||"#22C55E"],[a.negId,a.negColor||"#EF4444"]]
    )).flat()]
  );
  const [btnColors, setBtnColors] = useState(()=>{
    try{ const s=localStorage.getItem("rubromap_btn_colors"); return s?JSON.parse(s):DEFAULT_BTN_COLORS; }
    catch(e){ return DEFAULT_BTN_COLORS; }
  });
  const [showColorEditor, setShowColorEditor] = useState(false);
  const [editColorId,     setEditColorId]     = useState(null);

  const saveBtnColor=(id, color)=>{
    const next={...btnColors,[id]:color};
    setBtnColors(next);
    try{ localStorage.setItem("rubromap_btn_colors", JSON.stringify(next)); }catch(e){}
  };
  const resetBtnColors=()=>{
    setBtnColors(DEFAULT_BTN_COLORS);
    try{ localStorage.removeItem("rubromap_btn_colors"); }catch(e){}
    setShowColorEditor(false);
  };
  const getBtnColor=useCallback(id=>btnColors[id]||DEFAULT_BTN_COLORS[id]||"#666",[btnColors]);
  const [editMode, setEditMode] = useState(false);
  const [dragging, setDragging] = useState(null);

  const mRef=useRef(null), possRef=useRef(null);

  /* Cronômetro partida */
  useEffect(()=>{
    if(mRun) mRef.current=setInterval(()=>setMTime(t=>t+1),1000);
    else clearInterval(mRef.current);
    return()=>clearInterval(mRef.current);
  },[mRun]);

  /* Cronômetro posse */
  useEffect(()=>{
    clearInterval(possRef.current);
    if(mRun && possMode==="fla")
      possRef.current=setInterval(()=>setPossTime(p=>({...p,fla:p.fla+1})),1000);
    else if(mRun && possMode==="adv")
      possRef.current=setInterval(()=>setPossTime(p=>({...p,adv:p.adv+1})),1000);
    return()=>clearInterval(possRef.current);
  },[mRun,possMode]);

  const toggleTimer = () => {
    if(mRun){
      setMRun(false);
    } else {
      if(possMode==="pause") setShowPossModal(true);
      setMRun(true);
    }
  };

  const fmt=s=>String(Math.floor(s/60)).padStart(2,"0")+":"+String(s%60).padStart(2,"0");
  const possTotal=possTime.fla+possTime.adv||1;
  const flaPct=Math.round(possTime.fla/possTotal*100);
  const advPct=100-flaPct;

  const loadCat=key=>{
    setCatKey(key); setPlayers(mkPlayers(SQUADS[key]||[]));
    setSelPl(null); setShowCat(false);
  };

  const register=(actId, zoneId)=>{
    const aid=actId||selAct;
    const zid=zoneId!==undefined?zoneId:selZone;
    if(zid===null||zid===undefined||aid===null||aid===undefined) return;
    const aDef=SECTORS.flatMap(s=>s.actions).find(x=>x.id===aid||x.posId===aid||x.negId===aid);
    // Intercept goal actions — open goal position modal first
    if(aDef?.openGoalModal){
      setGoalModal({side:aDef.openGoalModal, actId:aid, zoneId:zid});
      setSelZone(null); setSelAct(null);
      return;
    }
    registerWithData(aid, zid);
  };

  const registerWithData=(aid, zid, goalSection)=>{
    const z=[...ZONES_P,...ZONES_L].find(x=>x.id===zid)||ZONES_P[zid];
    const pl=players.find(p=>p.id===selPl);
    const t=fmt(mTime);
    const aDef=SECTORS.flatMap(s=>s.actions).find(x=>x.id===aid||x.posId===aid||x.negId===aid);
    if(aDef?.scoreHome || goalSection) setScore(s=>({...s,fla:s.fla+1}));
    if(aDef?.scoreAway || (goalSection&&goalSection==="away_inc")) setScore(s=>({...s,adv:s.adv+1}));
    setTStats(prev=>({...prev,[aid]:prev[aid]+1}));
    setTZStats(prev=>({...prev,[zid]:{...prev[zid],[aid]:prev[zid][aid]+1}}));
    if(selPl) setPlayers(prev=>prev.map(p=>p.id!==selPl?p:{
      ...p,stats:{...p.stats,[aid]:p.stats[aid]+1},
      zStats:{...p.zStats,[zid]:{...p.zStats[zid],[aid]:p.zStats[zid][aid]+1}},
    }));
    const meta=getMeta(aid);
    const extraLabel=goalSection?" · "+goalSection:"";
    setHist(prev=>[{id:Date.now(),time:t,player:pl?.name||"Equipe",
      num:pl?.number||null,label:meta.label+extraLabel,color:meta.color,
      zone:z?.name||"—",actId:aid},...prev.slice(0,299)]);
    setFlashZ(zid);setToast(meta.label);
    setTimeout(()=>setFlashZ(null),700);
    setTimeout(()=>setToast(null),1800);
  };

  const zTotal=(zid,filt)=>{
    const st=tZStats[zid];
    if(!st) return 0;
    if(!filt||filt==="all") return Object.values(st).reduce((a,b)=>a+b,0);
    return st[filt]||0;
  };
  const maxZ=filt=>Math.max(...ZONES_P.map(z=>zTotal(z.id,filt)),1);

  /* Exportar dados */
  const exportData=(format)=>{
    const rows=hist.map(h=>({
      Tempo:h.time, Jogador:h.player, Numero:h.num||"",
      Acao:h.label, Zona:h.zone,
    }));
    if(format==="csv"){
      const header=Object.keys(rows[0]||{}).join(",");
      const body=rows.map(r=>Object.values(r).map(v=>`"${v}"`).join(",")).join("\n");
      download(`rubromap_${catKey.replace(" ","_")}.csv`,"text/csv",header+"\n"+body);
    } else {
      const xml=`<?xml version="1.0" encoding="UTF-8"?>\n<partida categoria="${catKey}">\n`+
        rows.map(r=>`  <evento tempo="${r.Tempo}" jogador="${r.Jogador}" numero="${r.Numero}" acao="${r.Acao}" zona="${r.Zona}"/>`).join("\n")+
        "\n</partida>";
      download(`rubromap_${catKey.replace(" ","_")}.xml`,"application/xml",xml);
    }
  };

  const download=(name,type,content)=>{
    const blob=new Blob([content],{type});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");
    a.href=url;a.download=name;a.click();URL.revokeObjectURL(url);
  };

  /* Drag live buttons */
  const moveLiveBtn=(fromId,toCol,toRow)=>{
    setLiveButtons(prev=>{
      const occupied=prev.find(b=>b.col===toCol&&b.row===toRow);
      return prev.map(b=>{
        if(b.id===fromId) return {...b,col:toCol,row:toRow};
        if(occupied&&b.id===occupied.id){
          const old=prev.find(x=>x.id===fromId);
          return {...b,col:old.col,row:old.row};
        }
        return b;
      });
    });
  };

  const canReg=selZone!==null&&selAct!==null;

  return(
    <div style={{minHeight:"100vh",background:C.bg,color:C.wh,
      fontFamily:"'Bebas Neue','Anton',Impact,sans-serif",overflowX:"hidden"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Rajdhani:wght@500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:3px;height:3px}
        ::-webkit-scrollbar-thumb{background:${C.red};border-radius:2px}
        @keyframes fz{0%{opacity:.1;transform:scale(.85)}55%{opacity:1;transform:scale(1.14)}100%{opacity:1;transform:scale(1)}}
        @keyframes ta{0%{opacity:0;transform:translateX(-50%) translateY(14px)}15%,76%{opacity:1;transform:translateX(-50%) translateY(0)}100%{opacity:0}}
        @keyframes rp{0%,100%{box-shadow:0 0 0 0 rgba(232,0,28,.7)}55%{box-shadow:0 0 0 14px rgba(232,0,28,0)}}
        @keyframes pm{0%{opacity:0;transform:translate(-50%,-50%) scale(.92)}100%{opacity:1;transform:translate(-50%,-50%) scale(1)}}
        .fz{animation:fz .42s ease}
        .zb{cursor:pointer;transition:background .1s,border .1s}
        .ab{transition:all .1s;cursor:pointer;border:none}
        .ab:hover{filter:brightness(1.22);transform:translateY(-1px)}
        .hr:hover .db{opacity:1!important}
        input,select{background:#080808;border:1px solid ${C.bdr2};color:${C.wh};
          border-radius:5px;padding:6px 9px;font-family:'Rajdhani',sans-serif;
          font-size:13px;font-weight:600;outline:none}
        input::placeholder{color:#333}
        select option{background:#0A0A0A}
        .live-cell{border:1px dashed transparent;border-radius:8px;transition:border .15s}
        .live-cell.edit-mode{border-color:#2A2A2A;cursor:grab}
        .live-cell.edit-mode:hover{border-color:#444}
      `}</style>

      {/* Toast */}
      {toast&&<div style={{position:"fixed",bottom:28,left:"50%",zIndex:9999,pointerEvents:"none",
        animation:"ta 1.8s ease forwards",background:"#1C0004",border:"2px solid "+C.red,
        borderRadius:10,padding:"10px 28px",fontFamily:"'Bebas Neue'",fontSize:22,
        letterSpacing:2,color:C.wh,boxShadow:"0 0 28px rgba(232,0,28,.6)"}}>{toast}</div>}

      {/* Modal Posse */}
      {showPossModal&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.75)",zIndex:8888,
          display:"flex",alignItems:"center",justifyContent:"center"}}
          onClick={()=>setShowPossModal(false)}>
          <div style={{background:"#0F0F0F",border:"2px solid "+C.red,borderRadius:14,
            padding:"28px 36px",textAlign:"center",minWidth:280,
            animation:"pm .25s ease",boxShadow:"0 0 40px rgba(232,0,28,.35)"}}
            onClick={e=>e.stopPropagation()}>
            <div style={{fontSize:14,color:C.grL,letterSpacing:3,fontFamily:"'Rajdhani',sans-serif",
              fontWeight:700,marginBottom:16}}>QUEM ESTÁ COM A POSSE?</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
              <button onClick={()=>{setPossMode("fla");setShowPossModal(false);}}
                style={{background:"rgba(232,0,28,.18)",border:"2px solid "+C.red,
                  color:C.red,borderRadius:10,padding:"14px",fontFamily:"'Bebas Neue'",
                  fontSize:20,letterSpacing:2,cursor:"pointer"}}>FLAMENGO</button>
              <button onClick={()=>{setPossMode("adv");setShowPossModal(false);}}
                style={{background:"rgba(59,130,246,.18)",border:"2px solid "+C.blue,
                  color:C.blue,borderRadius:10,padding:"14px",fontFamily:"'Bebas Neue'",
                  fontSize:20,letterSpacing:2,cursor:"pointer"}}>ADVERSÁRIO</button>
            </div>
            <button onClick={()=>{setPossMode("pause");setShowPossModal(false);}}
              style={{marginTop:10,background:"transparent",border:"1px solid #333",
                color:C.grL,borderRadius:8,padding:"8px 20px",fontFamily:"'Bebas Neue'",
                fontSize:14,letterSpacing:2,cursor:"pointer",width:"100%"}}>PULAR</button>
          </div>
        </div>
      )}

      {/* ── MODAL GOL ── */}
      {goalModal&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.82)",zIndex:8889,
          display:"flex",alignItems:"center",justifyContent:"center"}}
          onClick={()=>setGoalModal(null)}>
          <div style={{background:"#0E0E0E",
            border:"2px solid "+(goalModal.side==="home"?C.red:C.blue),
            borderRadius:14,padding:"24px 28px",minWidth:360,maxWidth:460,
            animation:"pm .22s ease",boxShadow:"0 0 40px rgba(0,0,0,.8)"}}
            onClick={e=>e.stopPropagation()}>
            <div style={{fontSize:13,color:goalModal.side==="home"?C.red:C.blue,
              letterSpacing:3,fontFamily:"'Bebas Neue'",marginBottom:14,textAlign:"center"}}>
              {goalModal.side==="home"?"GOL DO FLAMENGO — ONDE FOI O GOL?":"GOL SOFRIDO — ONDE ENTROU?"}
            </div>
            <GoalGrid side={goalModal.side} onSelect={section=>{
              const {actId,zoneId,side}=goalModal;
              if(side==="home") setScore(s=>({...s,fla:s.fla+1}));
              else setScore(s=>({...s,adv:s.adv+1}));
              registerWithData(actId, zoneId, section);
              setGoalModal(null);
            }}/>
            <button onClick={()=>{
              const {actId,zoneId,side}=goalModal;
              if(side==="home") setScore(s=>({...s,fla:s.fla+1}));
              else setScore(s=>({...s,adv:s.adv+1}));
              registerWithData(actId, zoneId, "");
              setGoalModal(null);
            }} style={{marginTop:12,display:"block",width:"100%",textAlign:"center",
              background:"transparent",border:"1px solid #2A2A2A",color:"#444",
              borderRadius:7,padding:"7px 0",fontFamily:"'Bebas Neue'",fontSize:13,
              letterSpacing:2,cursor:"pointer"}}>REGISTRAR SEM POSIÇÃO</button>
          </div>
        </div>
      )}

      {/* ── MODAL EDITOR DE CORES ── */}
      {showColorEditor&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.82)",zIndex:8889,
          display:"flex",alignItems:"center",justifyContent:"center"}}
          onClick={()=>setShowColorEditor(false)}>
          <div style={{background:"#0E0E0E",border:"2px solid "+C.gold,
            borderRadius:14,padding:"24px",width:"min(580px,96vw)",maxHeight:"88vh",
            overflowY:"auto",animation:"pm .22s ease",boxShadow:"0 0 40px rgba(0,0,0,.8)"}}
            onClick={e=>e.stopPropagation()}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
              <div style={{fontSize:16,color:C.gold,letterSpacing:3,fontFamily:"'Bebas Neue'"}}>
                EDITOR DE CORES DOS BOTÕES
              </div>
              <button onClick={resetBtnColors} style={{background:"rgba(239,68,68,.15)",
                border:"1px solid rgba(239,68,68,.4)",color:"#EF4444",borderRadius:6,
                padding:"5px 14px",fontFamily:"'Bebas Neue'",fontSize:12,letterSpacing:2,
                cursor:"pointer"}}>RESTAURAR PADRÃO</button>
            </div>
            {SECTORS.map(s=>(
              <div key={s.id} style={{marginBottom:18}}>
                <div style={{fontSize:10,color:s.color,letterSpacing:3,fontFamily:"'Bebas Neue'",
                  marginBottom:8,borderBottom:"1px solid "+s.color+"33",paddingBottom:4}}>
                  {s.label.toUpperCase()}
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:6}}>
                  {s.actions.map(a=>{
                    if(a.type==="single"){
                      const bc=getBtnColor(a.id);
                      return(
                        <label key={a.id} style={{display:"flex",alignItems:"center",gap:8,
                          background:"#141414",border:"1px solid #222",borderRadius:7,
                          padding:"7px 10px",cursor:"pointer"}}>
                          <input type="color" value={bc}
                            onChange={e=>saveBtnColor(a.id,e.target.value)}
                            style={{width:28,height:28,border:"none",borderRadius:4,
                              background:"none",cursor:"pointer",padding:0}}/>
                          <span style={{fontFamily:"'Bebas Neue'",fontSize:12,
                            color:C.grL,letterSpacing:.5,flex:1}}>{a.label}</span>
                          <span style={{width:10,height:10,borderRadius:"50%",
                            background:bc,display:"inline-block",flexShrink:0}}/>
                        </label>
                      );
                    }
                    const pC=getBtnColor(a.posId), nC=getBtnColor(a.negId);
                    return[
                      <label key={a.posId} style={{display:"flex",alignItems:"center",gap:8,
                        background:"#141414",border:"1px solid #222",borderRadius:7,
                        padding:"7px 10px",cursor:"pointer"}}>
                        <input type="color" value={pC}
                          onChange={e=>saveBtnColor(a.posId,e.target.value)}
                          style={{width:28,height:28,border:"none",borderRadius:4,
                            background:"none",cursor:"pointer",padding:0}}/>
                        <span style={{fontFamily:"'Bebas Neue'",fontSize:12,
                          color:C.grL,letterSpacing:.5,flex:1}}>{a.label} {a.posLabel}</span>
                        <span style={{width:10,height:10,borderRadius:"50%",
                          background:pC,display:"inline-block",flexShrink:0}}/>
                      </label>,
                      <label key={a.negId} style={{display:"flex",alignItems:"center",gap:8,
                        background:"#141414",border:"1px solid #222",borderRadius:7,
                        padding:"7px 10px",cursor:"pointer"}}>
                        <input type="color" value={nC}
                          onChange={e=>saveBtnColor(a.negId,e.target.value)}
                          style={{width:28,height:28,border:"none",borderRadius:4,
                            background:"none",cursor:"pointer",padding:0}}/>
                        <span style={{fontFamily:"'Bebas Neue'",fontSize:12,
                          color:C.grL,letterSpacing:.5,flex:1}}>{a.label} {a.negLabel}</span>
                        <span style={{width:10,height:10,borderRadius:"50%",
                          background:nC,display:"inline-block",flexShrink:0}}/>
                      </label>
                    ];
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ═══ HEADER ═══ */}
      <header style={{background:"linear-gradient(90deg,"+C.blk+" 0%,#1C0004 42%,#1C0004 58%,"+C.blk+" 100%)",
        borderBottom:"3px solid "+C.red,padding:"9px 16px",
        display:"flex",alignItems:"center",justifyContent:"space-between",
        gap:12,flexWrap:"wrap",boxShadow:"0 3px 32px rgba(232,0,28,.28)"}}>

        {/* Logo */}
        <div style={{display:"flex",alignItems:"center",gap:11}}>
          <img src={"data:image/png;base64,"+LOGO_B64}
            style={{width:46,height:46,objectFit:"contain",
              filter:"drop-shadow(0 0 10px rgba(232,0,28,.7))"}} alt="CRF"/>
          <div>
            <div style={{fontSize:28,letterSpacing:7,lineHeight:.88,color:C.wh}}>RUBROMAP</div>
            <div style={{fontSize:8,color:C.gold,letterSpacing:2.5,
              fontFamily:"'Rajdhani',sans-serif",fontWeight:600}}>
              ANÁLISE DE DESEMPENHO
            </div>
          </div>
        </div>

        {/* Placar */}
        <div style={{display:"flex",alignItems:"center",gap:7}}>
          <div style={{textAlign:"center"}}>
            <div style={{fontSize:8,color:C.grL,letterSpacing:2,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>FLAMENGO</div>
            <div style={{fontSize:52,color:C.red,lineHeight:.84,fontFamily:"'Bebas Neue'"}}>{score.fla}</div>
          </div>
          <div style={{fontSize:20,color:C.gr,padding:"0 5px"}}>×</div>
          <div style={{textAlign:"center"}}>
            <div style={{fontSize:8,color:C.grL,letterSpacing:2,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>ADVERSÁRIO</div>
            <div style={{fontSize:52,color:C.grL,lineHeight:.84,fontFamily:"'Bebas Neue'"}}>{score.adv}</div>
          </div>

        </div>

        {/* Cronômetro + Posse */}
        <div style={{display:"flex",flexDirection:"column",gap:7}}>
          <div style={{display:"flex",alignItems:"center",gap:7}}>
            <div style={{fontFamily:"monospace",fontSize:32,letterSpacing:3,
              color:mRun?C.red:C.grL,background:C.blk,border:"1px solid "+C.bdr,
              borderRadius:8,padding:"4px 14px",transition:"all .3s",
              boxShadow:mRun?"0 0 16px rgba(232,0,28,.52)":"none"}}>{fmt(mTime)}</div>
            <button onClick={toggleTimer} style={lBtn(mRun?"#444":C.red)}>{mRun?"PAUSAR":"INICIAR"}</button>
            <button onClick={()=>{setMRun(false);setMTime(0);setPossMode("pause");}}
              style={lBtn("#1C1C1C")}>RESET</button>
          </div>
          {/* Posse */}
          <div style={{background:"#080808",border:"1px solid "+C.bdr,borderRadius:8,padding:"6px 10px"}}>
            <div style={{fontSize:8,color:C.grL,letterSpacing:2.5,textAlign:"center",
              fontFamily:"'Rajdhani',sans-serif",fontWeight:700,marginBottom:5}}>POSSE DE BOLA</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:3,marginBottom:5}}>
              {[{mode:"fla",label:"FLAMENGO",color:C.red},
                {mode:"pause",label:"PAUSA",color:"#3A3A3A"},
                {mode:"adv",label:"ADVERSÁRIO",color:C.blue}].map(({mode,label,color})=>{
                const on=possMode===mode;
                return(
                  <button key={mode} onClick={()=>setPossMode(mode)} style={{
                    background:on?color:"transparent",border:"1px solid "+(on?color:C.bdr),
                    color:on?C.wh:C.grL,borderRadius:5,padding:"5px 3px",
                    fontFamily:"'Bebas Neue'",fontSize:9,letterSpacing:1,cursor:"pointer",
                    transition:"all .15s",boxShadow:on?"0 0 8px "+color+"99":"none"}}>{label}</button>
                );
              })}
            </div>
            <div style={{display:"flex",alignItems:"center",gap:4}}>
              <span style={{fontFamily:"'Bebas Neue'",fontSize:12,color:C.red,minWidth:28,textAlign:"right"}}>{flaPct}%</span>
              <div style={{flex:1,height:7,background:"#181818",borderRadius:4,overflow:"hidden"}}>
                <div style={{width:flaPct+"%",height:"100%",
                  background:"linear-gradient(90deg,"+C.red+","+C.gold+")",transition:"width .6s"}}/>
              </div>
              <span style={{fontFamily:"'Bebas Neue'",fontSize:12,color:C.blue,minWidth:28}}>{advPct}%</span>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",marginTop:3}}>
              <span style={{fontSize:9,color:C.red,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>{fmt(possTime.fla)}</span>
              <span style={{fontSize:9,color:C.blue,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>{fmt(possTime.adv)}</span>
            </div>
          </div>
        </div>

        {/* Nav */}
        <nav style={{display:"flex",flexDirection:"column",gap:4}}>
          {[["ao_vivo","ANÁLISE"],
            ["heatmap","MAPA DE CALOR"],["stats","ESTATÍSTICAS"],["elenco","ELENCO"]].map(([id,lb])=>(
            <button key={id} onClick={()=>setView(id)} style={{
              background:view===id?C.red:"transparent",color:view===id?C.wh:C.grL,
              border:"1px solid "+(view===id?C.red:C.bdr),borderRadius:6,padding:"6px 14px",
              fontFamily:"'Bebas Neue'",fontSize:12,letterSpacing:2,cursor:"pointer",
              transition:"all .2s",boxShadow:view===id?"0 0 12px rgba(232,0,28,.4)":"none",
              textAlign:"left"}}>
              {lb}
            </button>
          ))}
          <button onClick={()=>setShowColorEditor(true)} style={{
            background:"rgba(200,160,48,.12)",border:"1px solid "+C.gold,
            color:C.gold,borderRadius:6,padding:"6px 10px",fontFamily:"'Bebas Neue'",
            fontSize:11,letterSpacing:2,cursor:"pointer",textAlign:"center",marginTop:2}}>
            CORES DOS BOTÕES
          </button>
          {hist.length>0&&(
            <div style={{display:"flex",gap:3,marginTop:4}}>
              <button onClick={()=>exportData("csv")} style={{
                ...lBtn(C.gold),fontSize:11,letterSpacing:1,padding:"5px 10px",flex:1,textAlign:"center"}}>
                CSV
              </button>
              <button onClick={()=>exportData("xml")} style={{
                ...lBtn(C.goldL),fontSize:11,letterSpacing:1,padding:"5px 10px",flex:1,textAlign:"center"}}>
                XML
              </button>
            </div>
          )}
        </nav>
      </header>

      <main style={{padding:"12px 14px",maxWidth:1400,margin:"0 auto"}}>

        {/* ═══ PARTIDA AO VIVO ═══ */}
        {view==="ao_vivo"&&(
          <LiveView
            zones={ZONES_L} selZone={selZone} setSelZone={setSelZone}
            selAct={selAct} setSelAct={setSelAct}
            selPl={selPl} setSelPl={setSelPl}
            players={players} tStats={tStats} tZStats={tZStats}
            maxZ={maxZ("all")} flashZ={flashZ}
            liveButtons={liveButtons} setLiveButtons={setLiveButtons}
            editMode={editMode} setEditMode={setEditMode}
            register={register}
            hist={hist} setHist={setHist}
            getBtnColor={getBtnColor}
            showColorEditor={showColorEditor} setShowColorEditor={setShowColorEditor}
          />
        )}

        {/* ═══ MAPA DE CALOR ═══ */}
        {view==="heatmap"&&(
          <div style={{display:"grid",gridTemplateColumns:"1fr 280px",gap:14}}>
            <div style={{display:"flex",flexDirection:"column",gap:11}}>
              <Card title={"MAPA DE CALOR"+(heatFilt!=="all"?" · "+getMeta(heatFilt).label:"")}>
                <FieldMap zones={ZONES_P} landscape={false} selZone={null} onZone={()=>{}}
                  flashZ={null} tZStats={tZStats} maxZ={maxZ(heatFilt)} filterAct={heatFilt}/>
              </Card>
              <Card title="INTENSIDADE POR ZONA">
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4}}>
                  {ZONES_P.map(z=>{
                    const tot=zTotal(z.id,heatFilt),mx=maxZ(heatFilt);
                    return(
                      <div key={z.id} style={{display:"flex",gap:6,alignItems:"center",
                        fontFamily:"'Rajdhani',sans-serif",fontSize:11}}>
                        <span style={{color:C.grL,minWidth:110,fontWeight:600}}>{z.name}</span>
                        <div style={{flex:1,height:9,background:"#131313",borderRadius:3,overflow:"hidden"}}>
                          <div style={{width:(tot/mx*100)+"%",height:"100%",
                            background:"linear-gradient(90deg,"+C.red+","+C.gold+")",transition:"width .4s"}}/>
                        </div>
                        <span style={{color:C.wh,minWidth:18,textAlign:"right",fontWeight:700,fontSize:12}}>{tot}</span>
                      </div>
                    );
                  })}
                </div>
              </Card>
            </div>
            <Card title="FILTRAR AÇÃO">
              <div style={{display:"flex",flexDirection:"column",gap:4}}>
                <button onClick={()=>setHeatFilt("all")} style={filtBtn(heatFilt==="all",C.gold)}>
                  TODAS AS AÇÕES
                </button>
                {SECTORS.map(s=>(
                  <div key={s.id} style={{marginBottom:4}}>
                    <div style={{fontSize:9,color:s.color,letterSpacing:2,
                      fontFamily:"'Bebas Neue'",marginBottom:3,
                      borderBottom:"1px solid "+s.color+"33",paddingBottom:2}}>{s.label.toUpperCase()}</div>
                    <div style={{display:"flex",flexDirection:"column",gap:3}}>
                      {s.actions.map(a=>a.type==="single"
                        ?<button key={a.id} onClick={()=>setHeatFilt(a.id)}
                          style={filtBtn(heatFilt===a.id,s.color)}>{a.label}</button>
                        :[<button key={a.posId} onClick={()=>setHeatFilt(a.posId)}
                          style={filtBtn(heatFilt===a.posId,a.posColor||C.posL)}>
                          {a.label}: {a.posLabel}</button>,
                          <button key={a.negId} onClick={()=>setHeatFilt(a.negId)}
                          style={filtBtn(heatFilt===a.negId,a.negColor||C.negL)}>
                          {a.label}: {a.negLabel}</button>]
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          </div>
        )}

        {/* ═══ ESTATÍSTICAS ═══ */}
        {view==="stats"&&(
          <div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:16}}>
              <Card title="POSSE DE BOLA">
                <div style={{display:"flex",gap:14,alignItems:"center"}}>
                  <div style={{textAlign:"center"}}>
                    <div style={{fontSize:8,color:C.red,letterSpacing:2,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>FLAMENGO</div>
                    <div style={{fontSize:38,color:C.red,fontFamily:"'Bebas Neue'"}}>{fmt(possTime.fla)}</div>
                    <div style={{fontSize:22,color:C.red,fontFamily:"'Bebas Neue'"}}>{flaPct}%</div>
                  </div>
                  <div style={{flex:1,height:12,background:"#131313",borderRadius:6,overflow:"hidden"}}>
                    <div style={{width:flaPct+"%",height:"100%",background:"linear-gradient(90deg,"+C.red+","+C.gold+")"}}/>
                  </div>
                  <div style={{textAlign:"center"}}>
                    <div style={{fontSize:8,color:C.blue,letterSpacing:2,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>ADVERSÁRIO</div>
                    <div style={{fontSize:38,color:C.blue,fontFamily:"'Bebas Neue'"}}>{fmt(possTime.adv)}</div>
                    <div style={{fontSize:22,color:C.blue,fontFamily:"'Bebas Neue'"}}>{advPct}%</div>
                  </div>
                </div>
              </Card>
              <Card title="EXPORTAR DADOS">
                <div style={{display:"flex",flexDirection:"column",gap:8,alignItems:"center",paddingTop:8}}>
                  <div style={{fontSize:12,color:C.grL,fontFamily:"'Rajdhani',sans-serif",fontWeight:600}}>
                    {hist.length} eventos registrados
                  </div>
                  <div style={{display:"flex",gap:10}}>
                    <button onClick={()=>exportData("csv")} style={{
                      ...lBtn(C.gold),fontSize:16,letterSpacing:2,padding:"10px 22px"}}>
                      EXPORTAR CSV
                    </button>
                    <button onClick={()=>exportData("xml")} style={{
                      ...lBtn(C.goldL),fontSize:16,letterSpacing:2,padding:"10px 22px"}}>
                      EXPORTAR XML
                    </button>
                  </div>
                </div>
              </Card>
            </div>
            {SECTORS.map(s=>(
              <div key={s.id} style={{marginBottom:18}}>
                <div style={{fontSize:13,color:s.color,letterSpacing:3,marginBottom:10,
                  fontFamily:"'Bebas Neue'",borderBottom:"1px solid "+s.color+"33",paddingBottom:5}}>
                  {s.label.toUpperCase()}
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:7}}>
                  {s.actions.map(a=>a.type==="single"
                    ?<StatCard key={a.id} label={a.label} val={tStats[a.id]} color={s.color}/>
                    :[<StatCard key={a.posId} label={`${a.label} ${a.posLabel}`} val={tStats[a.posId]} color={a.posColor||C.posL}/>,
                      <StatCard key={a.negId} label={`${a.label} ${a.negLabel}`} val={tStats[a.negId]} color={a.negColor||C.negL}/>]
                  )}
                </div>
              </div>
            ))}
            <div style={{fontSize:13,color:C.gold,letterSpacing:3,marginBottom:10,
              fontFamily:"'Bebas Neue'",borderBottom:"1px solid "+C.gold+"33",paddingBottom:5}}>
              POR JOGADOR
            </div>
            {players.map(p=>{
              const tot=Object.values(p.stats).reduce((a,b)=>a+b,0);
              return(
                <div key={p.id} style={{background:C.card,border:"1px solid "+C.bdr,
                  borderRadius:9,padding:11,marginBottom:7}}>
                  <div style={{display:"flex",gap:9,alignItems:"center",marginBottom:7}}>
                    <span style={{background:C.red,borderRadius:4,padding:"1px 7px",
                      fontFamily:"'Bebas Neue'",fontSize:14}}>#{p.number||"—"}</span>
                    <span style={{fontFamily:"'Bebas Neue'",fontSize:16,flex:1}}>{p.name}</span>
                    <span style={{color:C.grL,fontSize:10,fontFamily:"'Rajdhani',sans-serif",
                      border:"1px solid "+C.bdr,borderRadius:4,padding:"1px 7px"}}>{p.pos}</span>
                    <span style={{color:C.grL,fontSize:10,fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>{tot} lances</span>
                  </div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:4}}>
                    {ALL_IDS.filter(id=>p.stats[id]>0).map(id=>{
                      const m=getMeta(id);
                      return <span key={id} style={{background:m.color+"18",border:"1px solid "+m.color+"44",
                        borderRadius:4,padding:"2px 7px",fontSize:10,color:m.color,
                        fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>{m.label}: {p.stats[id]}</span>;
                    })}
                    {tot===0&&<span style={{color:"#222",fontSize:11,fontFamily:"'Rajdhani',sans-serif"}}>Sem lances</span>}
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* ═══ ELENCO ═══ */}
        {view==="elenco"&&(
          <ElencoView players={players} setPlayers={setPlayers}
            catKey={catKey} loadCat={loadCat} showCat={showCat} setShowCat={setShowCat}/>
        )}
      </main>
    </div>
  );
}

/* ── PARTIDA AO VIVO ────────────────────────────────────────────── */
function LiveView({zones,selZone,setSelZone,selAct,setSelAct,selPl,setSelPl,
  players,tStats,tZStats,maxZ,flashZ,liveButtons,setLiveButtons,
  editMode,setEditMode,register,hist,setHist,
  getBtnColor,showColorEditor,setShowColorEditor}){

  const GRID_COLS=6, GRID_ROWS=4;
  const [dragSrc,setDragSrc]=useState(null);
  const [dropTarget,setDropTarget]=useState(null);

  const btnAt=(c,r)=>liveButtons.find(b=>b.col===c&&b.row===r);

  const handleDrop=(toCol,toRow)=>{
    if(dragSrc===null) return;
    const srcBtn=liveButtons.find(b=>b.id===dragSrc);
    if(!srcBtn) return;
    const destBtn=btnAt(toCol,toRow);
    setLiveButtons(prev=>prev.map(b=>{
      if(b.id===dragSrc) return {...b,col:toCol,row:toRow};
      if(destBtn&&b.id===destBtn.id) return {...b,col:srcBtn.col,row:srcBtn.row};
      return b;
    }));
    setDragSrc(null);setDropTarget(null);
  };

  return(
    <div style={{display:"flex",flexDirection:"column",gap:12}}>

      {/* Barra superior: campo landscape + jogador */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 200px",gap:12}}>
        {/* Campo landscape */}
        <Card title="ZONA DO LANCE — CLIQUE PARA SELECIONAR">
          <FieldMap zones={zones} landscape={true}
            selZone={selZone} onZone={id=>setSelZone(id===selZone?null:id)}
            flashZ={flashZ} tZStats={tZStats} maxZ={maxZ} filterAct={null}/>
          {selZone!==null&&(
            <div style={{textAlign:"center",fontSize:11,color:C.gold,marginTop:5,
              fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>
              Zona: {zones[selZone]?.name}
            </div>
          )}
        </Card>

        {/* Jogador */}
        <Card title="JOGADOR">
          <PlayerList players={players} selPl={selPl} setSelPl={setSelPl} compact/>
        </Card>
      </div>

      {/* Grid de botões de ação */}
      <Card title={
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <span>AÇÕES — {editMode?"MODO EDIÇÃO (ARRASTE PARA REORGANIZAR)":selZone!==null?"CLIQUE NA AÇÃO PARA REGISTRAR":"SELECIONE UMA ZONA NO CAMPO"}</span>
          <button onClick={()=>setEditMode(e=>!e)} style={{
            ...lBtn(editMode?C.posL:"#444"),fontSize:11,letterSpacing:1,
            padding:"3px 12px",fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>
            {editMode?"SALVAR LAYOUT":"EDITAR LAYOUT"}
          </button>
        </div>
      }>
        <div style={{display:"grid",
          gridTemplateColumns:`repeat(${GRID_COLS},1fr)`,
          gridTemplateRows:`repeat(${GRID_ROWS},1fr)`,
          gap:6}}>
          {Array.from({length:GRID_ROWS},(_,r)=>Array.from({length:GRID_COLS},(_,c)=>{
            const btn=btnAt(c,r);
            const isDrop=dropTarget&&dropTarget.col===c&&dropTarget.row===r;
            if(!btn) return(
              <div key={`${c}-${r}`}
                onDragOver={e=>{e.preventDefault();setDropTarget({col:c,row:r});}}
                onDragLeave={()=>setDropTarget(null)}
                onDrop={()=>handleDrop(c,r)}
                style={{height:72,border:"1px dashed "+(isDrop?"#444":"#1A1A1A"),
                  borderRadius:8,opacity:.4}}/>
            );
            const meta=getMeta(btn.id);
            const bc=getBtnColor?getBtnColor(btn.id):meta.color;
            const sel=selAct===btn.id;
            return(
              <div key={btn.id}
                draggable={editMode}
                onDragStart={()=>setDragSrc(btn.id)}
                onDragOver={e=>{e.preventDefault();setDropTarget({col:c,row:r});}}
                onDragLeave={()=>setDropTarget(null)}
                onDrop={()=>handleDrop(c,r)}
                onClick={()=>{
                  if(editMode) return;
                  if(selZone!==null){
                    register(btn.id, selZone);
                  } else {
                    setSelAct(btn.id===selAct?null:btn.id);
                  }
                }}
                style={{
                  height:72,borderRadius:8,cursor:editMode?"grab":"pointer",
                  background:sel?"#0A0A0A":bc+"20",
                  border:"1.5px solid "+(sel?"#2A2A2A":isDrop?"#555":bc),
                  display:"flex",flexDirection:"column",alignItems:"center",
                  justifyContent:"center",gap:3,padding:"6px 4px",
                  boxShadow:sel?"none":"0 0 10px "+bc+"33",
                  transition:"all .12s",userSelect:"none",
                  outline:isDrop&&editMode?"2px dashed #555":"none",
                }}>
                <span style={{fontFamily:"'Bebas Neue'",fontSize:22,fontWeight:900,
                  color:sel?"#2A2A2A":C.wh,lineHeight:1,
                  background:sel?"#181818":bc,
                  borderRadius:20,padding:"0 10px",minWidth:34,textAlign:"center"}}>
                  {tStats[btn.id]}
                </span>
                <span style={{fontFamily:"'Bebas Neue'",fontSize:12,letterSpacing:.5,
                  color:sel?"#2A2A2A":bc,textAlign:"center",lineHeight:1.1,
                  maxWidth:"95%"}}>
                  {meta.label}
                </span>
              </div>
            );
          }))}
        </div>
      </Card>

      {/* Histórico */}
      <HistPanel hist={hist} setHist={setHist} compact/>
    </div>
  );
}

/* ── CAMPO (portrait ou landscape) ─────────────────────────── */
function FieldMap({zones,landscape,selZone,onZone,flashZ,tZStats,maxZ,filterAct}){
  const b64=landscape?CAMPO_L_B64:CAMPO_P_B64;
  return(
    <div style={{position:"relative",width:"100%",display:"block",
      borderRadius:6,overflow:"hidden",lineHeight:0,
      boxShadow:"0 0 0 1px #1A3A1A"}}>
      <img src={"data:image/jpeg;base64,"+b64}
        style={{display:"block",width:"100%",height:"auto"}} alt="campo"/>
      <div style={{position:"absolute",inset:0}}>
        {zones.map(z=>{
          const tot=filterAct&&filterAct!=="all"
            ?(tZStats[z.id]?.[filterAct]||0)
            :Object.values(tZStats[z.id]||{}).reduce((a,b)=>a+b,0);
          const intensity=tot/Math.max(maxZ,1);
          const sel=selZone===z.id;
          const flash=flashZ===z.id;
          return(
            <div key={z.id} className={"zb"+(flash?" fz":"")}
              onClick={()=>onZone(z.id)} title={z.name}
              style={{
                position:"absolute",
                left:(z.x1*100)+"%",top:(z.y1*100)+"%",
                width:((z.x2-z.x1)*100)+"%",height:((z.y2-z.y1)*100)+"%",
                background:sel
                  ?"rgba(232,0,28,.44)"
                  :tot>0?"rgba(232,0,28,"+(0.08+intensity*0.42)+")"
                  :"rgba(0,0,0,.02)",
                border:sel?"2px solid rgba(232,0,28,.92)":"1px solid rgba(255,255,255,.05)",
                boxShadow:sel?"inset 0 0 14px rgba(232,0,28,.4)":"none",
                display:"flex",alignItems:"center",justifyContent:"center",
              }}>
              {tot>0&&(
                <span style={{background:"rgba(0,0,0,.72)",color:"#fff",
                  borderRadius:8,padding:"0 5px",fontSize:9,fontWeight:800,
                  fontFamily:"monospace",pointerEvents:"none"}}>{tot}</span>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ── GRID DE AÇÕES (análise completa) ─────────────────────── */
function ActionGrid({sector,selAct,setSelAct,tStats,getBtnColor}){
  const singles=sector.actions.filter(a=>a.type==="single");
  const splits=sector.actions.filter(a=>a.type==="split");
  return(
    <div style={{display:"flex",flexDirection:"column",gap:5}}>
      {singles.length>0&&(
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(110px,1fr))",gap:4}}>
          {singles.map(a=>{
            const sel=selAct===a.id;
            const bc=getBtnColor?getBtnColor(a.id):sector.color;
            return(
              <button key={a.id} className="ab"
                onClick={()=>setSelAct(a.id===selAct?null:a.id)}
                style={{background:sel?"#0C0C0C":bc+"22",
                  border:"1.5px solid "+(sel?"#333":bc),borderRadius:7,
                  padding:"6px 7px",color:sel?"#333":bc,
                  display:"flex",flexDirection:"column",alignItems:"center",gap:3,
                  fontFamily:"'Bebas Neue'",
                  boxShadow:sel?"none":"0 0 8px "+bc+"33"}}>
                <span style={{fontSize:20,fontWeight:900,color:sel?"#222":C.wh,
                  background:sel?"#1A1A1A":bc,
                  borderRadius:20,padding:"0 8px",minWidth:28,textAlign:"center"}}>{tStats[a.id]}</span>
                <span style={{fontSize:11,letterSpacing:.4,textAlign:"center",lineHeight:1.1}}>{a.label}</span>
              </button>
            );
          })}
        </div>
      )}
      {splits.map(a=>{
        const sP=selAct===a.posId,sN=selAct===a.negId;
        const pC=getBtnColor?getBtnColor(a.posId):(a.posColor||C.posL);
        const nC=getBtnColor?getBtnColor(a.negId):(a.negColor||C.negL);
        return(
          <div key={a.id}>
            <div style={{fontSize:9,color:"#3A3A3A",fontFamily:"'Rajdhani',sans-serif",
              fontWeight:700,letterSpacing:1,marginBottom:3}}>{a.label}</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",borderRadius:7,
              overflow:"hidden",border:"1px solid "+C.bdr2}}>
              <button className="ab" onClick={()=>setSelAct(a.posId===selAct?null:a.posId)}
                style={{background:sP?"#0C0C0C":pC+"22",borderRight:"1px solid "+C.bdr2,
                  color:sP?"#333":pC,padding:"7px 8px",display:"flex",
                  alignItems:"center",justifyContent:"space-between",gap:5,
                  fontFamily:"'Bebas Neue'",fontSize:14,letterSpacing:.5,
                  boxShadow:sP?"none":"inset 0 0 0 1px "+pC+"55"}}>
                <span>{a.posLabel}</span>
                <span style={{background:sP?"#1A1A1A":pC,color:sP?"#333":"#050505",
                  borderRadius:20,padding:"0 7px",fontSize:13,fontWeight:900,
                  minWidth:22,textAlign:"center"}}>{tStats[a.posId]}</span>
              </button>
              <button className="ab" onClick={()=>setSelAct(a.negId===selAct?null:a.negId)}
                style={{background:sN?"#0C0C0C":nC+"22",color:sN?"#333":nC,
                  padding:"7px 8px",display:"flex",alignItems:"center",
                  justifyContent:"space-between",gap:5,fontFamily:"'Bebas Neue'",
                  fontSize:14,letterSpacing:.5,
                  boxShadow:sN?"none":"inset 0 0 0 1px "+nC+"55"}}>
                <span>{a.negLabel}</span>
                <span style={{background:sN?"#1A1A1A":nC,color:sN?"#333":"#050505",
                  borderRadius:20,padding:"0 7px",fontSize:13,fontWeight:900,
                  minWidth:22,textAlign:"center"}}>{tStats[a.negId]}</span>
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

/* ── HISTÓRICO ───────────────────────────────────────────── */
function HistPanel({hist,setHist,compact}){
  return(
    <Card title={"HISTÓRICO  ("+hist.length+")"}>
      {hist.length>0&&(
        <button onClick={()=>setHist([])} style={{
          display:"block",width:"100%",textAlign:"center",marginBottom:7,
          ...lBtn("#1C1C1C"),fontFamily:"'Rajdhani',sans-serif",fontSize:10,
          letterSpacing:1,fontWeight:700}}>LIMPAR HISTÓRICO</button>
      )}
      {hist.length===0
        ?<div style={{color:C.grL,fontSize:12,textAlign:"center",padding:"14px 0",
          fontFamily:"'Rajdhani',sans-serif"}}>Nenhum lance registrado</div>
        :<div style={{maxHeight:compact?180:220,overflowY:"auto",display:"flex",flexDirection:"column",gap:2}}>
          {hist.map((h,i)=>(
            <div key={h.id} className="hr" style={{display:"flex",gap:6,alignItems:"center",
              padding:"4px 7px",borderRadius:5,background:i===0?"#1A0003":"transparent",
              borderLeft:"3px solid "+(i===0?h.color:"transparent")}}>
              <span style={{color:"#333",fontFamily:"monospace",minWidth:34,fontSize:10}}>{h.time}</span>
              <span style={{color:"#4A4A4A",minWidth:22,fontSize:10,fontFamily:"'Rajdhani',sans-serif",fontWeight:600}}>
                {h.num?"#"+h.num:"EQ"}</span>
              <span style={{color:"#777",minWidth:65,fontFamily:"'Rajdhani',sans-serif",fontWeight:600,fontSize:11}}>{h.player}</span>
              <span style={{color:h.color,flex:1,fontFamily:"'Rajdhani',sans-serif",fontWeight:700,fontSize:11}}>{h.label}</span>
              <button className="db" onClick={()=>setHist(p=>p.filter(x=>x.id!==h.id))}
                style={{opacity:0,background:"transparent",border:"1px solid #252525",
                  color:"#EF4444",cursor:"pointer",fontSize:10,borderRadius:3,
                  padding:"1px 5px",fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>X</button>
            </div>
          ))}
        </div>
      }
    </Card>
  );
}

/* ── ELENCO ──────────────────────────────────────────────── */
function ElencoView({players,setPlayers,catKey,loadCat,showCat,setShowCat}){
  const [editId,setEditId]=useState(null);
  const [form,setForm]=useState({name:"",number:"",pos:"Atacante"});
  const [add,setAdd]=useState({name:"",number:"",pos:"Atacante"});

  const startEdit=p=>{setEditId(p.id);setForm({name:p.name,number:p.number,pos:p.pos});};
  const saveEdit=()=>{setPlayers(p=>p.map(x=>x.id===editId?{...x,...form}:x));setEditId(null);};
  const delP=id=>setPlayers(p=>p.filter(x=>x.id!==id));
  const addP=()=>{
    if(!add.name.trim()) return;
    setPlayers(p=>[...p,{id:Date.now(),name:add.name.trim(),
      number:add.number||"",pos:add.pos,stats:initSt(),zStats:initZSt()}]);
    setAdd({name:"",number:"",pos:"Atacante"});
  };

  return(
    <div>
      <div style={{position:"relative",marginBottom:14}}>
        <button onClick={()=>setShowCat(s=>!s)} style={{
          display:"flex",alignItems:"center",gap:10,width:"100%",textAlign:"left",
          background:"#0C0C0C",border:"2px solid "+C.red,borderRadius:10,
          padding:"12px 18px",cursor:"pointer",boxShadow:"0 0 16px rgba(232,0,28,.18)"}}>
          <span style={{fontSize:9,color:C.grL,letterSpacing:3,
            fontFamily:"'Rajdhani',sans-serif",fontWeight:700}}>CATEGORIA</span>
          <span style={{fontFamily:"'Bebas Neue'",fontSize:26,color:C.red,letterSpacing:3,flex:1}}>
            {catKey.toUpperCase()}</span>
          <span style={{fontFamily:"'Bebas Neue'",fontSize:18,color:C.grL}}>
            {showCat?"▲":"▼"}</span>
        </button>
        {showCat&&(
          <div style={{position:"absolute",top:"calc(100% + 5px)",left:0,right:0,zIndex:200,
            background:"#0D0D0D",border:"1px solid "+C.bdr2,borderRadius:10,
            overflow:"hidden",boxShadow:"0 10px 36px rgba(0,0,0,.7)"}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr"}}>
              {CAT_LIST.map(cat=>(
                <button key={cat} onClick={()=>loadCat(cat)} style={{
                  background:cat===catKey?"#1C0004":"transparent",
                  border:"none",borderRight:"1px solid "+C.bdr,borderBottom:"1px solid "+C.bdr,
                  color:cat===catKey?C.red:C.grL,padding:"12px 10px",cursor:"pointer",
                  fontFamily:"'Bebas Neue'",fontSize:17,letterSpacing:2,
                  transition:"background .12s",textAlign:"center"}}>
                  {cat}
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      <Card title="ADICIONAR JOGADOR">
        <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"flex-end"}}>
          <FG label="NOME" flex={2} minW={120}>
            <input value={add.name} onChange={e=>setAdd(f=>({...f,name:e.target.value}))} placeholder="Nome completo"/>
          </FG>
          <FG label="Nº" width={65}>
            <input value={add.number} type="number" onChange={e=>setAdd(f=>({...f,number:e.target.value}))} placeholder="00"/>
          </FG>
          <FG label="POSIÇÃO" flex={1} minW={130}>
            <select value={add.pos} onChange={e=>setAdd(f=>({...f,pos:e.target.value}))}>
              {POSITIONS.map(p=><option key={p}>{p}</option>)}
            </select>
          </FG>
          <button onClick={addP} style={{...lBtn(C.red),padding:"8px 18px",alignSelf:"flex-end"}}>ADICIONAR</button>
        </div>
      </Card>

      <div style={{fontSize:9,color:C.grL,letterSpacing:2,fontFamily:"'Rajdhani',sans-serif",
        fontWeight:700,margin:"14px 0 8px"}}>{players.length} JOGADORES · {catKey}</div>

      <div style={{display:"flex",flexDirection:"column",gap:5}}>
        {players.length===0&&(
          <div style={{color:C.grL,fontSize:13,textAlign:"center",padding:"22px 0",
            fontFamily:"'Rajdhani',sans-serif",border:"1px dashed "+C.bdr,borderRadius:8}}>
            Nenhum jogador nesta categoria. Adicione acima ou selecione outra categoria.
          </div>
        )}
        {players.map(p=>(
          <div key={p.id} style={{background:C.card,border:"1px solid "+(editId===p.id?C.red:C.bdr),
            borderRadius:8,padding:"9px 12px",boxShadow:editId===p.id?"0 0 10px rgba(232,0,28,.2)":"none"}}>
            {editId===p.id?(
              <div style={{display:"flex",gap:7,flexWrap:"wrap",alignItems:"flex-end"}}>
                <FG label="NOME" flex={2} minW={120}>
                  <input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))}/>
                </FG>
                <FG label="Nº" width={65}>
                  <input value={form.number} type="number" onChange={e=>setForm(f=>({...f,number:e.target.value}))}/>
                </FG>
                <FG label="POSIÇÃO" flex={1} minW={130}>
                  <select value={form.pos} onChange={e=>setForm(f=>({...f,pos:e.target.value}))}>
                    {POSITIONS.map(pos=><option key={pos}>{pos}</option>)}
                  </select>
                </FG>
                <div style={{display:"flex",gap:5,alignSelf:"flex-end"}}>
                  <button onClick={saveEdit} style={lBtn(C.posL)}>SALVAR</button>
                  <button onClick={()=>setEditId(null)} style={lBtn("#333")}>CANCELAR</button>
                </div>
              </div>
            ):(
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <span style={{background:C.red,borderRadius:4,padding:"2px 8px",
                  fontFamily:"'Bebas Neue'",fontSize:15,minWidth:34,textAlign:"center"}}>
                  {p.number||"—"}</span>
                <span style={{fontFamily:"'Bebas Neue'",fontSize:17,flex:1}}>{p.name}</span>
                <span style={{color:C.grL,fontSize:10,fontFamily:"'Rajdhani',sans-serif",
                  border:"1px solid "+C.bdr,borderRadius:4,padding:"1px 7px"}}>{p.pos}</span>
                <button onClick={()=>startEdit(p)} style={lBtn("#333")}>EDITAR</button>
                <button onClick={()=>delP(p.id)} style={{background:"rgba(239,68,68,.12)",
                  border:"1px solid rgba(239,68,68,.35)",color:C.negL,borderRadius:6,
                  padding:"6px 12px",fontFamily:"'Bebas Neue'",fontSize:13,letterSpacing:2,cursor:"pointer"}}>
                  EXCLUIR
                </button>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

/* ── LISTA DE JOGADORES (altura dinâmica) ───────────────────── */
// Calcula quantos jogadores cabem no espaço restante após o campo
function PlayerList({ players, selPl, setSelPl, compact }) {
  const containerRef = useRef(null);
  const [listH, setListH] = useState(550);

  useEffect(() => {
    // Mede o elemento pai (Card) e determina altura disponível para a lista
    if (!containerRef.current) return;
    const card = containerRef.current.closest('[data-player-card]');
    if (!card) return;
    const updateH = () => {
      const available = card.clientHeight - 36; // 36 = título do Card
      setListH(Math.max(80, available));
    };
    updateH();
    const ro = new ResizeObserver(updateH);
    ro.observe(card);
    return () => ro.disconnect();
  }, []);

  return (
    <div ref={containerRef}
      style={{ height: compact ? 550 : listH, overflowY: "auto",
        display: "flex", flexDirection: "column", gap: 3 }}>
      <PBtn active={selPl === null} onClick={() => setSelPl(null)}>
        <span style={{ fontFamily: "'Rajdhani',sans-serif", fontWeight: 700,
          color: selPl === null ? C.gold : C.grL, fontSize: 13 }}>EQUIPE</span>
      </PBtn>
      {players.map(p => (
        <PBtn key={p.id} active={selPl === p.id}
          onClick={() => setSelPl(p.id === selPl ? null : p.id)}>
          <span style={{ background: selPl === p.id ? C.red : "#1C1C1C", borderRadius: 4,
            padding: "2px 7px", fontFamily: "'Bebas Neue'", fontSize: 13,
            minWidth: 26, textAlign: "center" }}>{p.number || "—"}</span>
          <span style={{ fontFamily: "'Rajdhani',sans-serif", fontWeight: 700,
            flex: 1, textAlign: "left", fontSize: 13 }}>{p.name}</span>
          <span style={{ fontSize: 10, color: C.grL,
            fontFamily: "'Rajdhani',sans-serif" }}>{p.pos}</span>
        </PBtn>
      ))}
    </div>
  );
}

/* ── GRADE DO GOL (9 zonas: 3 colunas × 3 linhas) ──────────── */
// Baseado na imagem: Superior(roxo), Centro(ocre), Inferior(vermelho)
// Cada faixa tem: Esquerdo | Meio | Direito
function GoalGrid({side, onSelect}){
  const accentColor = side==="home" ? "#E8001C" : "#3B82F6";
  const rows=[
    {label:"Superior", color:"#5C3D8F", sections:[
      {id:"sup_esq", label:"Superior\nEsquerdo"},
      {id:"sup_mei", label:"Superior\nMeio"},
      {id:"sup_dir", label:"Superior\nDireito"},
    ]},
    {label:"Centro",   color:"#B8860B", sections:[
      {id:"ctr_esq", label:"Centro\nEsquerdo"},
      {id:"ctr_mei", label:"Centro"},
      {id:"ctr_dir", label:"Centro\nDireito"},
    ]},
    {label:"Inferior", color:"#8B1A1A", sections:[
      {id:"inf_esq", label:"Inferior\nEsquerdo"},
      {id:"inf_mei", label:"Inferior\nMeio"},
      {id:"inf_dir", label:"Inferior\nDireito"},
    ]},
  ];
  return(
    <div style={{position:"relative",borderRadius:10,overflow:"hidden",
      border:"3px solid rgba(255,255,255,.25)",boxShadow:"0 0 0 1px rgba(255,255,255,.1)"}}>
      {/* Trave superior */}
      <div style={{background:"rgba(255,255,255,.15)",height:10,
        borderBottom:"3px solid rgba(255,255,255,.5)"}}/>
      {/* Grade */}
      <div style={{display:"grid",gridTemplateRows:"1fr 1fr 1fr"}}>
        {rows.map((row,ri)=>(
          <div key={row.id} style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",
            borderBottom: ri<2?"2px solid rgba(255,255,255,.3)":"none"}}>
            {row.sections.map((sec,ci)=>(
              <button key={sec.id} onClick={()=>onSelect(sec.id)}
                className="ab"
                style={{
                  background:row.color+(ci===1?"EE":"CC"),
                  border:"none",
                  borderRight: ci<2?"1px solid rgba(255,255,255,.3)":"none",
                  padding:"18px 8px",cursor:"pointer",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  color:"rgba(255,255,255,.95)",
                  fontFamily:"'Bebas Neue'",fontSize:13,letterSpacing:.8,
                  textAlign:"center",lineHeight:1.3,whiteSpace:"pre-line",
                  transition:"filter .1s",
                  outline:"none",
                }}
                onMouseEnter={e=>{e.currentTarget.style.filter="brightness(1.35)";}}
                onMouseLeave={e=>{e.currentTarget.style.filter="brightness(1)";}}
              >
                {sec.label}
              </button>
            ))}
          </div>
        ))}
      </div>
      {/* Postes */}
      <div style={{position:"absolute",top:10,left:0,bottom:0,width:8,
        background:"linear-gradient(to right,rgba(255,255,255,.6),rgba(255,255,255,.15))"}}/>
      <div style={{position:"absolute",top:10,right:0,bottom:0,width:8,
        background:"linear-gradient(to left,rgba(255,255,255,.6),rgba(255,255,255,.15))"}}/>
      {/* Rede de fundo */}
      <div style={{position:"absolute",inset:0,pointerEvents:"none",
        backgroundImage:"repeating-linear-gradient(0deg,rgba(255,255,255,.05) 0px,rgba(255,255,255,.05) 1px,transparent 1px,transparent 20px),repeating-linear-gradient(90deg,rgba(255,255,255,.05) 0px,rgba(255,255,255,.05) 1px,transparent 1px,transparent 20px)"}}/>
    </div>
  );
}

/* ── COMPONENTES AUXILIARES ──────────────────────────────── */
function Card({title,children,accent,flex,playerCard}){
  const c=accent||C.red;
  return(
    <div data-player-card={playerCard||undefined}
      style={{background:C.card,border:"1px solid "+C.bdr,borderRadius:10,padding:12,
      ...(flex?{display:"flex",flexDirection:"column",flex:1}:{})}}>
      {title&&<div style={{fontSize:11,color:c,letterSpacing:3,fontFamily:"'Bebas Neue'",
        marginBottom:9,borderBottom:"1px solid "+c+"24",paddingBottom:5}}>
        {typeof title==="string"?title:title}
      </div>}
      {children}
    </div>
  );
}
function PBtn({active,onClick,children}){
  return(
    <button onClick={onClick} style={{background:active?"#1A0003":"transparent",
      border:"1px solid "+(active?C.red:C.bdr),borderRadius:6,padding:"4px 8px",
      cursor:"pointer",display:"flex",alignItems:"center",gap:7,
      color:active?C.wh:C.grL,transition:"all .15s",width:"100%",
      boxShadow:active?"0 0 7px rgba(232,0,28,.22)":"none"}}>{children}</button>
  );
}
function FG({label,children,flex,width,minW}){
  return(
    <div style={{display:"flex",flexDirection:"column",gap:4,
      ...(flex?{flex}:{}),
      ...(width?{width}:{}),
      ...(minW?{minWidth:minW}:{})}}>
      <label style={{fontSize:9,color:C.grL,fontFamily:"'Rajdhani',sans-serif",
        fontWeight:700,letterSpacing:1}}>{label}</label>
      {children}
    </div>
  );
}
function StatCard({label,val,color}){
  return(
    <div style={{background:C.card,border:"1px solid "+(val>0?color+"44":C.bdr),
      borderRadius:8,padding:"8px 11px"}}>
      <div style={{fontSize:10,color:C.grL,fontFamily:"'Rajdhani',sans-serif",marginBottom:2}}>{label}</div>
      <div style={{fontSize:34,fontFamily:"'Bebas Neue'",color:val>0?color:"#1E1E1E"}}>{val}</div>
    </div>
  );
}
function lBtn(c){return{background:c+"22",border:"1px solid "+c,color:c,borderRadius:6,
  padding:"6px 13px",fontFamily:"'Bebas Neue'",fontSize:13,letterSpacing:2,
  cursor:"pointer",whiteSpace:"nowrap"};}
function sBtn(c){return{background:c+"44",border:"1px solid "+c,color:C.grL,borderRadius:5,
  padding:"3px 9px",fontSize:10,cursor:"pointer",fontFamily:"'Rajdhani',sans-serif",
  fontWeight:600,letterSpacing:1};}
function filtBtn(active,color){return{background:active?color+"20":"transparent",
  border:"1px solid "+(active?color:C.bdr2),color:active?color:C.grL,borderRadius:5,
  padding:"5px 9px",fontFamily:"'Bebas Neue'",fontSize:11,letterSpacing:1,cursor:"pointer",
  textAlign:"left",width:"100%",transition:"all .1s",
  boxShadow:active?"0 0 7px "+color+"44":"none"};}
